import os
import pandas as pd
from datetime import datetime

def task_func(excel_directory: str, file_name: str, column_name: str, start_date: str, end_date: str) -> pd.DataFrame:
    file_path = os.path.join(excel_directory, file_name)

    if not os.path.isfile(file_path):
        raise FileNotFoundError(f"The specified Excel file does not exist: {file_path}")

    try:
        df = pd.read_excel(file_path)
    except Exception as e:
        raise ValueError(f"Failed to read the Excel file: {e}")

    if column_name not in df.columns:
        raise ValueError(f"The specified column '{column_name}' does not exist in the DataFrame.")

    try:
        df[column_name] = pd.to_datetime(df[column_name], errors='raise')
    except Exception as e:
        raise ValueError(f"Failed to convert column '{column_name}' to datetime format: {e}")

    try:
        start_dt = datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.strptime(end_date, "%Y-%m-%d")
    except ValueError as e:
        raise ValueError(f"Invalid date format for start_date or end_date. Expected format: YYYY-MM-DD. Error: {e}")

    if start_dt > end_dt:
        raise ValueError("start_date cannot be later than end_date.")

    filtered_df = df[(df[column_name] >= start_dt) & (df[column_name] <= end_dt)]

    return filtered_df

import pandas as pd
import matplotlib.pyplot as plt
from statsmodels.tsa.seasonal import seasonal_decompose

def task_func(df, freq='D', decomposition_model='multiplicative'):
    if not isinstance(df, pd.DataFrame):
        raise ValueError("If 'df' is not a DataFrame")
    if 'value' not in df.columns:
        raise ValueError("If 'df' is not a DataFrame, lacks required columns, or contains invalid data types")
    if not pd.api.types.is_numeric_dtype(df['value']):
        raise ValueError("If 'df' is not a DataFrame, lacks required columns, or contains invalid data types")
    try:
        pd.tseries.frequencies.to_offset(freq)
    except (ValueError, TypeError):
        raise ValueError("If 'freq' is not a valid frequency string")
    if decomposition_model not in ['additive', 'multiplicative']:
        raise ValueError("If 'decomposition_model' is not 'additive' or 'multiplicative'")
    if not isinstance(df.index, pd.DatetimeIndex):
        try:
            df = df.copy()
            df.index = pd.to_datetime(df.index)
        except:
            raise ValueError("The DataFrame index must be datetime-like or convertible to datetime")
    period = pd.tseries.frequencies.to_offset(freq).n
    decomposition = seasonal_decompose(df['value'], model=decomposition_model, period=period)
    fig, ax = plt.subplots(figsize=(10, 6))
    decomposition.plot(ax=ax)
    plt.tight_layout()
    return decomposition, ax

import subprocess
import psutil
import time
import os

def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    cpu_usage = 0.0
    memory_usage = 0.0
    process = None
    start_time = time.time()

    try:
        process = subprocess.Popen([script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        proc = psutil.Process(process.pid)

        while True:
            if time.time() - start_time > timeout:
                if process.poll() is None:
                    process.terminate()
                    try:
                        process.wait(timeout=5)
                    except subprocess.TimeoutExpired:
                        process.kill()
                break

            if proc.is_running():
                try:
                    cpu_percent = proc.cpu_percent(interval=0.1)
                    cpu_usage += cpu_percent
                    memory_info = proc.memory_info()
                    memory_usage += memory_info.rss
                except (psutil.NoSuchProcess, psutil.ZombieProcess):
                    break
            else:
                break

            time.sleep(0.1)

    except Exception as e:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()
        raise e

    finally:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()

    return {
        'CPU Usage': cpu_usage,
        'Memory Usage': int(memory_usage)
    }

