def task_func(data):
    if not data:
        return {}, None

    for i, fruit_dict in enumerate(data):
        for fruit, quantity in fruit_dict.items():
            if quantity < 0:
                raise ValueError(f"Sales quantity for {fruit} in entry {i} is negative: {quantity}")

    total_sales = collections.defaultdict(int)
    for fruit_dict in data:
