import re
import socket

def task_func(ip_addresses: list) -> dict:
    result = {}
    for ip in ip_addresses:
        # Validate IP address format
        if re.match(r'^(\d{1,3}\.){3}\d{1,3}$', ip):
            try:
                # Attempt to resolve hostname
                hostname = socket.gethostbyaddr(ip)[0]
                result[ip] = hostname
            except socket.herror:
                # Hostname not found
                result[ip] = None
            except socket.gaierror:
                # Invalid IP address (though regex should catch this)
                result[ip] = None
        else:
            # Invalid IP format
            result[ip] = None
    return result

import rsa
import urllib.request
from hashlib import sha256

def task_func(url):
    public_key, private_key = rsa.newkeys(2048)
    try:
        with urllib.request.urlopen(url) as response:
            if response.getcode() != 200:
                raise ValueError(f"HTTP error: {response.getcode()}")
            content = response.read()
    except urllib.error.URLError as e:
        raise e
    except Exception as e:
        raise ValueError(f"Error retrieving URL content: {str(e)}")
    hash_object = sha256(content)
    hash_digest = hash_object.digest()
    try:
        signed_hash = rsa.sign(hash_digest, private_key, 'SHA-256')
    except rsa.pkcs1.VerificationError as e:
        raise rsa.pkcs1.VerificationError(f"Failed to sign hash: {str(e)}")
    return public_key, signed_hash.hex(), hash_digest

