def task_func(dir_path: str, pattern: str = '^EMP'):
    if not os.path.exists(dir_path):
        return pd.DataFrame(columns=['File', 'Size'])

    files = os.listdir(dir_path)
    matched_files = [f for f in files if re.match(pattern, f)]
    matched_files.sort()

    file_data = []

    for file_name in matched_files:
        file_path = os.path.join(dir_path, file_name)
        if os.path.isfile(file_path):
            try:
                with open(file_path, 'r') as f:
                    lines = [line.strip() for line in f.readlines() if line.strip()]

                is_ascending = all(lines[i] <= lines[i+1] for i in range(len(lines)-1)) if lines else True

                if is_ascending:
                    file_size = os.path.getsize(file_path)
                    file_data.append((file_name, file_size))
            except (IOError, OSError):
                continue

    return pd.DataFrame(file_data, columns=['File', 'Size'])

