# Constants
IP_REGEX = r'[0-9]+(?:\.[0-9]+){3}'
def task_func(API_URL):
    try:
        with urllib.request.urlopen(API_URL) as response:
            data = response.read().decode('utf-8')
            try:
                json_data = json.loads(data)
                if isinstance(json_data, dict):
                    for value in json_data.values():
                        if isinstance(value, str) and re.match(IP_REGEX, value):
                            return value
                elif isinstance(json_data, str) and re.match(IP_REGEX, json_data):
                    return json_data
            except json.JSONDecodeError:
                match = re.search(IP_REGEX, data)
                if match:
                    return match.group()
            raise ValueError("No valid IP address found in the response.")
    except Exception as e:
        raise Exception(f"API request failed: {str(e)}")

