import os
import re

def task_func(log_file_path: str, keywords: list):
    if not os.path.exists(log_file_path):
        return []

    with open(log_file_path, 'r') as file:
        lines = file.readlines()

    matched_lines = []
    for line in lines:
        line_lower = line.lower()
        if any(keyword.lower() in line_lower for keyword in keywords):
            matched_lines.append(line.strip())

    formatted_lines = []
    timestamp_pattern = re.compile(r'\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\]|\b(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\b')

    for line in matched_lines:
        match = timestamp_pattern.search(line)
        if match:
            timestamp = match.group(1) or match.group(2)
            message = re.sub(timestamp_pattern, '', line).strip()
            message = re.sub(r'\s+', ' ', message)
        else:
            timestamp = "UNKNOWN"
            message = line

        matched_keyword = None
        for keyword in keywords:
            if keyword.lower() in line.lower():
                matched_keyword = keyword
                break

        if matched_keyword:
            formatted_line = f"{matched_keyword:<20}{timestamp:<20}{message}"
            formatted_lines.append(formatted_line)

    return formatted_lines

