import numpy as np
import itertools

def task_func(data_list, file_name):
    if not data_list:
        with open(file_name, 'w') as f:
            pass
        return []

    # Convert data_list to a list of lists, replacing non-numeric values with np.nan
    processed_data = []
    for tup in data_list:
        row = []
        for i, val in enumerate(tup):
            if i == 0:
                row.append(val)  # Keep string at first position
            else:
                try:
                    row.append(float(val))
                except (ValueError, TypeError):
                    row.append(np.nan)
        processed_data.append(row)

    # Extract numerical columns (excluding first column)
    numerical_data = [row[1:] for row in processed_data]

    # Stack into a 2D array and compute mean along axis 0
    arr = np.array(numerical_data, dtype=float)
    means = np.nanmean(arr, axis=0)

    # Write results to file
    with open(file_name, 'w') as f:
        for i, mean in enumerate(means):
            f.write(f'Position {i+1}: {mean}\n')

    return means.tolist()

import os
import re
import hashlib

def task_func(path, delimiter):
    pattern = re.escape(delimiter)
    parts = re.split(f'({pattern})', path)
    components = []
    i = 0
    while i < len(parts):
        if parts[i] == delimiter:
            components.append(delimiter)
        else:
            if i + 1 < len(parts) and parts[i + 1] == delimiter:
                components.append(parts[i] + delimiter)
                i += 1
            else:
                components.append(parts[i])
        i += 1
    result = []
    current_path = ""
    for component in components:
        if component == delimiter:
            current_path += delimiter
        else:
            if current_path == "" and not component.endswith(delimiter):
                current_path = component
            elif current_path.endswith(delimiter) or component.startswith(delimiter):
                current_path += component
            else:
                current_path += delimiter + component
        if os.path.isfile(current_path):
            try:
                with open(current_path, 'rb') as f:
                    file_hash = hashlib.md5(f.read()).hexdigest()
                result.append((component, file_hash))
            except Exception:
                result.append((component, None))
        else:
            result.append((component, None))
    return result

