def task_func(x):
    if not x:
        return []
    keys = list(x.keys())
    if len(keys) == 1:
        return [keys[0]]
    min_length = float('inf')
    best_subsequence = []
    n = len(keys)
    for i in range(1, 2**n):
        subsequence = []
        for j in range(n):
            if i & (1 << j):
                subsequence.append(keys[j])
        total_length = sum(x[key] for key in subsequence)
        if total_length < min_length:
            min_length = total_length
            best_subsequence = subsequence
    return best_subsequence

