import json
from pathlib import Path
def task_func(directory: str) -> str:
    if not os.path.exists(directory):
        raise FileNotFoundError(f"The directory '{directory}' does not exist.")

    if not os.path.isdir(directory):
        raise NotADirectoryError(f"The path '{directory}' is not a directory.")

    abs_directory = os.path.abspath(directory)
    hashes = {}

    for root, _, files in os.walk(abs_directory):
        for file in files:
            file_path = os.path.join(root, file)
            rel_path = os.path.relpath(file_path, abs_directory)

            sha256_hash = hashlib.sha256()
            try:
                with open(file_path, "rb") as f:
                    for chunk in iter(lambda: f.read(4096), b""):
                        sha256_hash.update(chunk)
                hashes[rel_path] = sha256_hash.hexdigest()
            except (IOError, OSError) as e:
                print(f"Error reading file {file_path}: {e}")

    json_file_path = os.path.join(abs_directory, "hashes.json")

    try:
        with open(json_file_path, "w") as json_file:
            json.dump(hashes, json_file, indent=4)
    except (IOError, OSError) as e:
        raise IOError(f"Failed to write hashes to JSON file: {e}")

    return os.path.abspath(json_file_path)

