    if n < 1:
        raise ValueError("Input n must be a positive integer (n >= 1)")
    pairs = []
    unordered_pairs = combinations(range(1, n + 1), 2)
    for i, j in unordered_pairs:
        pairs.append((i, j))
        pairs.append((j, i))
    for i in range(1, n + 1):
        pairs.append((i, i))
    return pairs

