# Constants
def task_func(input_file, output_file):
    with open(input_file, 'r') as file:
        data = json.load(file)

    all_keys = set()
    for item in data:
        all_keys.update(item.keys())

    values_dict = {key: [] for key in all_keys}

    for item in data:
        for key in all_keys:
            if key in item:
                values_dict[key].append(item[key])

    result = {}
    for key in all_keys:
        values = values_dict[key]
        mean_val = np.mean(values)
        median_val = np.median(values)
        result[key] = {
            'mean': mean_val,
            'median': median_val
        }

    with open(output_file, 'w', newline='') as csvfile:
        fieldnames = ['key', 'mean', 'median']
        writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
        writer.writeheader()
        for key, stats in result.items():
            writer.writerow({
                'key': key,
                'mean': stats['mean'],
                'median': stats['median']
            })

    return result

