import json
import re
from collections import Counter

# Constants
REPLACE_NONE = "None"

def task_func(json_str):
    # Parse the JSON string into a Python dictionary
    data = json.loads(json_str)

    # Helper function to recursively remove None values
    def remove_none_values(obj):
        if isinstance(obj, dict):
            return {k: remove_none_values(v) for k, v in obj.items() if v is not None}
        elif isinstance(obj, list):
            return [remove_none_values(item) for item in obj if item is not None]
        else:
            return obj

    # Process the data by removing None values
    processed_data = remove_none_values(data)

    # Count the frequency of each unique value
    value_counts = Counter()

    def count_values(obj):
        if isinstance(obj, dict):
            for v in obj.values():
                count_values(v)
        elif isinstance(obj, list):
            for item in obj:
                count_values(item)
        else:
            value_counts[obj] += 1

    count_values(processed_data)

    # Replace all email addresses with the placeholder "None"
    def replace_emails(obj):
        if isinstance(obj, dict):
            return {k: replace_emails(v) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [replace_emails(item) for item in obj]
        elif isinstance(obj, str):
            # Regex pattern for email addresses
            email_pattern = r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'
            return re.sub(email_pattern, REPLACE_NONE, obj)
        else:
            return obj

    final_data = replace_emails(processed_data)

    # Return the result
    return {
        "data": final_data,
        "value_counts": value_counts
    }

