            ['tar', '-czf', backup_file] + log_files,
            check=True
        )
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Failed to create backup archive: {e}")

    for log_file in log_files:
        os.remove(log_file)

    return backup_file

