import pandas as pd
import folium
from geopy.geocoders import Photon

def task_func(dic):
    geolocator = Photon(user_agent="geoapiExercises")

    def resolve_location(location):
        if isinstance(location, (tuple, list)) and len(location) == 2:
            return location
        elif isinstance(location, str):
            try:
                location_data = geolocator.geocode(location)
                if location_data:
                    return (location_data.latitude, location_data.longitude)
                else:
                    raise ValueError(f"Could not resolve location: {location}")
            except Exception as e:
                raise ValueError(f"Geocoding failed for {location}: {e}")
        else:
            raise ValueError(f"Unsupported location format: {location}")

    locations = []
    for key, value in dic.items():
        try:
            lat_lon = resolve_location(value)
            locations.append({
                'name': key,
                'latitude': lat_lon[0],
                'longitude': lat_lon[1]
            })
        except Exception as e:
            print(f"Error processing location '{key}': {e}")
            continue

    if locations:
        avg_lat = sum(loc['latitude'] for loc in locations) / len(locations)
        avg_lon = sum(loc['longitude'] for loc in locations) / len(locations)
        map_center = [avg_lat, avg_lon]
    else:
        map_center = [0, 0]

    m = folium.Map(location=map_center, zoom_start=2)

    for loc in locations:
        folium.Marker(
            location=[loc['latitude'], loc['longitude']],
            popup=loc['name'],
            tooltip=loc['name']
        ).add_to(m)

    return m

