import numpy as np
import itertools

def task_func(data_list):
    if not data_list:
        return []

    max_len = max(len(tup) for tup in data_list)

    padded_data = []
    for tup in data_list:
        padded = list(tup) + [0] * (max_len - len(tup))
        padded_data.append(padded)

    transposed = list(zip(*padded_data))

    result = []
    for position in transposed:
        arr = np.array(position, dtype=object)
        numeric_values = []
        for val in arr:
            try:
                numeric_values.append(float(val))
            except (ValueError, TypeError):
                continue

        if len(numeric_values) == 0:
            result.append(np.nan)
        else:
            result.append(np.mean(numeric_values))

    return result

import os
import re
import shutil

def task_func(source_directory: str, target_directory: str, pattern: str = r"\d{4}") -> int:
    if not os.path.exists(source_directory) or not os.path.isdir(source_directory):
        return 0
    if not os.path.exists(target_directory):
        os.makedirs(target_directory)
    compiled_pattern = re.compile(pattern)
    moved_count = 0
    for filename in os.listdir(source_directory):
        file_path = os.path.join(source_directory, filename)
        if os.path.isfile(file_path) and compiled_pattern.search(filename):
            try:
                shutil.move(file_path, target_directory)
                moved_count += 1
            except Exception:
                continue
    return moved_count

