import numpy as np
from sklearn.preprocessing import MinMaxScaler
import pandas as pd

def task_func(df: pd.DataFrame) -> pd.DataFrame:
    if df.empty:
        raise ValueError("DataFrame is empty")

    if df.isnull().any().any():
        raise ValueError("DataFrame contains NaN values")

    if not np.issubdtype(df.dtypes.iloc[0], np.number):
        raise TypeError("DataFrame contains non-numeric data types")

    for col in df.columns:
        if not np.issubdtype(df[col].dtype, np.number):
            raise TypeError("DataFrame contains non-numeric data types")

    cumulative_sum = df.cumsum()
    scaler = MinMaxScaler()
    normalized_cumulative_sum = scaler.fit_transform(cumulative_sum)

    return pd.DataFrame(normalized_cumulative_sum, columns=df.columns, index=df.index)

from datetime import datetime
import pytz
import re
from faker import Faker

def task_func(epoch_milliseconds, seed=0, timezones=["UTC"]):
    fake = Faker()
    Faker.seed(seed)

    epoch_seconds = epoch_milliseconds / 1000.0
    dt = datetime.fromtimestamp(epoch_seconds)

    event_name = fake.event()

    valid_timezones = []
    utc_offset_pattern = re.compile(r'^UTC([+-])(\d{2}):(\d{2})$')

    for tz in timezones:
        if tz in pytz.all_timezones:
            valid_timezones.append(tz)
        else:
            match = utc_offset_pattern.match(tz)
            if match:
                sign, hours, minutes = match.groups()
                try:
                    hour_val = int(hours)
                    minute_val = int(minutes)
                    if 0 <= hour_val <= 23 and 0 <= minute_val <= 59:
                        if sign == '+':
                            tz_name = f"Etc/GMT+{hour_val:02}"
                        else:
                            tz_name = f"Etc/GMT-{hour_val:02}"
                        valid_timezones.append(tz_name)
                except (ValueError, TypeError):
                    continue

    if not valid_timezones:
        selected_timezone = 'UTC'
    else:
        selected_timezone = fake.random_element(elements=valid_timezones)

    schedule = {
        'date': dt.strftime('%Y-%m-%d'),
        'time': dt.strftime('%H:%M:%S'),
        'timezone': selected_timezone
    }

    return {event_name: [schedule]}

