import socket
import select
import queue
from datetime import datetime, timedelta

def task_func(
    server_address="localhost", server_port=12345, buffer_size=1024, run_duration=5
):
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setblocking(False)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)

    try:
        server_socket.bind((server_address, server_port))
        server_socket.listen(5)
    except socket.error as e:
        return f"Failed to bind or listen on {server_address}:{server_port}. Error: {e}"

    inputs = [server_socket]
    outputs = []
    message_queues = {}

    start_time = datetime.now()
    status_message = f"Server started successfully on {server_address}:{server_port}. Running for {run_duration} seconds."
    print(status_message)

    try:
        while True:
            elapsed_time = datetime.now() - start_time
            if elapsed_time >= timedelta(seconds=run_duration):
                break

            readable, writable, exceptional = select.select(inputs, outputs, inputs, 1.0)

            for s in exceptional:
                print(f"Exceptional condition on socket {s}")
                if s in inputs:
                    inputs.remove(s)
                if s in outputs:
                    outputs.remove(s)
                s.close()
                if s in message_queues:
                    del message_queues[s]

            for s in readable:
                if s is server_socket:
                    try:
                        client_socket, client_address = s.accept()
                        client_socket.setblocking(False)
                        inputs.append(client_socket)
                        message_queues[client_socket] = queue.Queue()
                        print(f"Accepted connection from {client_address}")
                    except socket.error as e:
                        print(f"Error accepting connection: {e}")
                else:
                    try:
                        data = s.recv(buffer_size)
                        if data:
                            current_time = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                            response = f"{data.decode('utf-8')} [Server Time: {current_time}]\n"
                            message_queues[s].put(response.encode('utf-8'))
                            if s not in outputs:
                                outputs.append(s)
                        else:
                            print(f"Client {s.getpeername()} disconnected")
                            if s in outputs:
                                outputs.remove(s)
                            if s in inputs:
                                inputs.remove(s)
                            s.close()
                            if s in message_queues:
                                del message_queues[s]
                    except socket.error as e:
                        print(f"Error reading from client {s.getpeername()}: {e}")
                        if s in inputs:
                            inputs.remove(s)
                        if s in outputs:
                            outputs.remove(s)
                        s.close()
                        if s in message_queues:
                            del message_queues[s]

            for s in writable:
                try:
                    if not message_queues[s].empty():
                        next_msg = message_queues[s].get_nowait()
                        s.send(next_msg)
                    else:
                        if s in outputs:
                            outputs.remove(s)
                except socket.error as e:
                    print(f"Error writing to client {s.getpeername()}: {e}")
                    if s in inputs:
                        inputs.remove(s)
                    if s in outputs:
                        outputs.remove(s)
                    s.close()
                    if s in message_queues:
                        del message_queues[s]

    except Exception as e:
        return f"Server encountered an unexpected error: {e}"

    finally:
        for s in inputs:
            if s is not server_socket:
                try:
                    s.close()
                except:
                    pass
        try:
            server_socket.close()
        except:
            pass
        inputs.clear()
        outputs.clear()
        message_queues.clear()

    end_time = datetime.now()
    duration = (end_time - start_time).seconds
    return f"Server ran successfully for {duration} seconds. Shut down gracefully"

