        if not os.path.exists(current_path):
            raise FileNotFoundError(f"Path does not exist: {current_path}")

        if not os.path.isdir(current_path):
            raise ValueError(f"Path is not a directory: {current_path}")

        try:
            usage = shutil.disk_usage(current_path)
            result.append((comp, {
                'total': usage.total,
                'used': usage.used,
                'free': usage.free
            }))
        except Exception as e:
            raise RuntimeError(f"Could not get disk usage for {current_path}: {e}")

    return result

