import re
import pandas as pd
from datetime import datetime
def task_func(log_file):
    pattern = r'^(.+?): \[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\] - (.+)$'
    log_data = []
    try:
        with open(log_file, 'r') as file:
            lines = file.readlines()
        valid_entries = 0
        for line_num, line in enumerate(lines, 1):
            line = line.strip()
            if not line:
                continue
            match = re.match(pattern, line)
            if not match:
                continue
            message_type, timestamp_str, message = match.groups()
            try:
                datetime.strptime(timestamp_str, '%Y-%m-%d %H:%M:%S')
            except ValueError:
                raise ValueError(f"Invalid timestamp format in line {line_num}: {timestamp_str}")
            log_data.append({
                'message_type': message_type.strip(),
                'timestamp': timestamp_str,
                'message': message.strip()
            })
            valid_entries += 1
        if valid_entries == 0:
            raise ValueError("No valid log entries found in the file.")
        df = pd.DataFrame(log_data)
        csv_file = log_file.replace('.log', '_structured.csv')
        df.to_csv(csv_file, index=False)
        return csv_file
    except FileNotFoundError:
        raise FileNotFoundError(f"Log file not found: {log_file}")
    except Exception as e:
        raise e

