def find_shared_elements(list1, list2):
    set1 = set(list1)
    shared_elements = set()
    for element in list2:
        if element in set1:
            shared_elements.add(element)
    return list(shared_elements)

def find_n_largest(numbers, n):
    if not isinstance(numbers, list):
        raise ValueError("Input must be a list")
    if len(numbers) == 0:
        raise ValueError("Input list cannot be empty")
    if not all(isinstance(x, int) for x in numbers):
        raise ValueError("All elements in the list must be integers")
    if not isinstance(n, int):
        raise ValueError("n must be an integer")
    if n <= 0:
        raise ValueError("n must be a positive integer")
    if n > len(numbers):
        raise ValueError("n cannot be greater than the length of the list")
    return sorted(numbers, reverse=True)[:n]

def square_elements(numbers):
    squared_values = []
    for num in numbers:
        squared_values.append(num ** 2)
    return squared_values

def contains_underscore_separated_lowercase(s):
    import re
    pattern = r'^[a-z]+(?:_[a-z]+)*$'
    return bool(re.match(pattern, s))

def contains_duplicate(arr):
    seen = set()
    for num in arr:
        if num in seen:
            return True
        seen.add(num)
    return False

def is_one_less_than_twice_reverse(n):
    reverse_n = int(str(n)[::-1])
    return n == 2 * reverse_n - 1

def count_substrings_with_digit_sum_equal_length(s):
    count = 0
    n = len(s)
    for i in range(n):
        digit_sum = 0
        for j in range(i, n):
            digit_sum += int(s[j])
            length = j - i + 1
            if digit_sum == length:
                count += 1
    return count

def max_difference_pairs(tuples_list):
    if len(tuples_list) < 2:
        return 0
    max_diff = 0
    for i in range(len(tuples_list)):
        for j in range(i + 1, len(tuples_list)):
            diff = abs(tuples_list[i][0] - tuples_list[j][0]) + abs(tuples_list[i][1] - tuples_list[j][1])
            max_diff = max(max_diff, diff)
    return max_diff

def flatten_and_sum(lst):
    total = 0
    for item in lst:
        if isinstance(item, list):
            total += flatten_and_sum(item)
        else:
            total += item
    return total

def is_monotonic(arr):
    if len(arr) <= 2:
        return True

    increasing = True
    decreasing = True

    for i in range(1, len(arr)):
        if arr[i] < arr[i-1]:
            increasing = False
        if arr[i] > arr[i-1]:
            decreasing = False

    return increasing or decreasing

def contains_sublist(main_list, sublist):
    if not sublist:
        return True
    if len(sublist) > len(main_list):
