def sum_amicable_numbers(n):
    def sum_divisors(num):
        total = 1
        for i in range(2, int(num ** 0.5) + 1):
            if num % i == 0:
                total += i
                if i != num // i:
                    total += num // i
        return total

    amicable_sum = 0
    visited = set()

    for i in range(2, n + 1):
        if i in visited:
            continue
        sum_i = sum_divisors(i)
        if sum_i != i and sum_i <= n:
