def solve_linear_diophantine(a, b, n):
    import math
    g = math.gcd(abs(a), abs(b))
    if n % g != 0:
        return None
    def extended_gcd(x, y):
        if y == 0:
            return x, 1, 0
        else:
            g, x1, y1 = extended_gcd(y, x % y)
            x0 = y1
            y0 = x1 - (x // y) * y1
            return g, x0, y0
    g, x0, y0 = extended_gcd(abs(a), abs(b))
    if a < 0:
        x0 = -x0
    if b < 0:
        y0 = -y0
    scale = n // g
    x = x0 * scale
    y = y0 * scale
    return (x, y)

