        first_pos = -1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == target:
                first_pos = mid
                right = mid - 1
            elif arr[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return first_pos

    def find_last(arr, n, target):
        left, right = 0, n - 1
        last_pos = -1
        while left <= right:
            mid = (left + right) // 2
            if arr[mid] == target:
                last_pos = mid
                left = mid + 1
            elif arr[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return last_pos

    first = find_first(arr, n, target)
    if first == -1:
        return False
    last = find_last(arr, n, target)
    count = last - first + 1
    return count > n // 2

