def create_next_bigger_number(n):
    digits = [int(d) for d in str(n)]
    length = len(digits)

    pivot_index = -1
    for i in range(length - 2, -1, -1):
        if digits[i] < digits[i + 1]:
            pivot_index = i
            break
    if pivot_index == -1:
        return None

    candidate_index = -1
    min_greater = float('inf')
    for i in range(pivot_index + 1, length):
        if digits[i] > digits[pivot_index] and digits[i] < min_greater:
            min_greater = digits[i]
            candidate_index = i

    if candidate_index == -1:
        return None

    digits[pivot_index], digits[candidate_index] = digits[candidate_index], digits[pivot_index]

    right_side = digits[pivot_index + 1:]
    right_side.sort()
    digits[pivot_index + 1:] = right_side

    result = int(''.join(map(str, digits)))

    if len(str(result)) != length:
        return None

    if result <= n:
        return None

    return result

