    if len(segments) != 4:
        raise ValueError("IP address must have exactly 4 segments separated by dots")

    cleaned_segments = []
    for segment in segments:
        if not segment:
            raise ValueError("IP segment cannot be empty")
        if not segment.isdigit():
            raise ValueError(f"Invalid IP segment: '{segment}' is not a valid number")

        if segment == '0':
            cleaned_segments.append('0')
