def find_median_sorted_arrays(nums1, nums2):
    n = len(nums1)

    if n == 0:
        return 0.0

    if n == 1:
        return (nums1[0] + nums2[0]) / 2.0

    if nums1[n-1] <= nums2[0]:
        return (nums1[n-1] + nums2[0]) / 2.0
    if nums2[n-1] <= nums1[0]:
        return (nums2[n-1] + nums1[0]) / 2.0

    left, right = 0, n

    while left <= right:
        mid1 = (left + right) // 2
        mid2 = (2 * n + 1) // 2 - mid1

        left1 = nums1[mid1 - 1] if mid1 > 0 else float('-inf')
        right1 = nums1[mid1] if mid1 < n else float('inf')
        left2 = nums2[mid2 - 1] if mid2 > 0 else float('-inf')
        right2 = nums2[mid2] if mid2 < n else float('inf')

        if left1 <= right2 and left2 <= right1:
            total_len = 2 * n
            if total_len % 2 == 1:
                return float(max(left1, left2))
            else:
                return float((max(left1, left2) + min(right1, right2)) / 2.0)
        elif left1 > right2:
            right = mid1 - 1
        else:
            left = mid1 + 1

    return 0.0

