}

def task_func():
    class PostRequestHandler(http.server.BaseHTTPRequestHandler):
        def do_POST(self):
            content_length = int(self.headers.get('Content-Length', 0))
            if content_length == 0:
                self.send_error(400, "No data key in request")
                return
            try:
                post_data = self.rfile.read(content_length)
            except Exception:
                self.send_error(400, "Invalid JSON")
                return
            content_type = self.headers.get('Content-Type', '')
            if not content_type.startswith('application/json'):
                self.send_error(400, "Content-Type header is not application/json")
                return
            try:
                json_data = json.loads(post_data.decode('utf-8'))
            except json.JSONDecodeError:
                self.send_error(400, "Invalid JSON")
                return
            if 'data' not in json_data:
                self.send_error(400, "No data key in request")
                return
            self.send_response(200)
            self.send_header('Content-Type', 'application/json')
            self.send_header('Content-Length', str(len(json.dumps(SUCCESS_RESPONSE).encode('utf-8'))))
            self.end_headers()
            self.wfile.write(json.dumps(SUCCESS_RESPONSE).encode('utf-8'))
