import subprocess
import psutil
import time
import os
def task_func(script_path: str, timeout=10) -> dict:
    if not os.path.exists(script_path):
        raise FileNotFoundError(f"Script not found: {script_path}")

    cpu_usage = 0.0
    memory_usage = 0.0
    start_time = time.time()
    process = None

    try:
        process = subprocess.Popen([script_path], stdout=subprocess.PIPE, stderr=subprocess.PIPE)
        proc = psutil.Process(process.pid)

        while True:
            if process.poll() is not None:
                break

            if time.time() - start_time > timeout:
                process.terminate()
                try:
                    process.wait(timeout=5)
                except subprocess.TimeoutExpired:
                    process.kill()
                break

            try:
                if proc.is_running():
                    cpu_percent = proc.cpu_percent(interval=0.1)
                    memory_info = proc.memory_info()
                    memory_usage += memory_info.rss
                    cpu_usage += cpu_percent
                else:
                    break
            except psutil.NoSuchProcess:
                break

            time.sleep(0.1)

        if process.poll() is not None:
            try:
                proc = psutil.Process(process.pid)
                if proc.is_running():
                    memory_info = proc.memory_info()
                    memory_usage += memory_info.rss
            except psutil.NoSuchProcess:
                pass

    except Exception as e:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()
        raise e

    finally:
        if process and process.poll() is None:
            process.terminate()
            try:
                process.wait(timeout=5)
            except subprocess.TimeoutExpired:
                process.kill()

    return {
        'CPU Usage': cpu_usage,
        'Memory Usage': int(memory_usage)
    }

import pandas as pd
import re

def task_func(data, mapping):
    df = data.copy()
    pattern = re.compile(r'\b[A-Z\.]+\b')

    def replace_acronyms_in_string(text):
        if not isinstance(text, str):
            return text

        max_iter = 10
        for _ in range(max_iter):
            matches = pattern.findall(text)
            if not matches:
                break
            replaced = False
            for acronym in matches:
                normalized = acronym.replace('.', '')
                if normalized in mapping:
                    full_form = mapping[normalized]
                    text = text.replace(acronym, full_form)
                    replaced = True
            if not replaced:
                break
        return text

    return df.applymap(replace_acronyms_in_string)

