    except ValueError as e:
        raise e
    except Exception as e:
        raise Exception(f"Unexpected I/O error: {str(e)}") from e

    raw_lines1 = [delimiter.join([f'{quotechar}{item}{quotechar}' if (quotechar in item or delimiter in item or '\n' in item) else item for item in line]) for line in lines1]
    raw_lines2 = [delimiter.join([f'{quotechar}{item}{quotechar}' if (quotechar in item or delimiter in item or '\n' in item) else item for item in line]) for line in lines2]

    diff_lines = list(ndiff(raw_lines1, raw_lines2))

