def task_func(dir_path: str, predicates: list) -> dict:
    path = Path(dir_path)
    if not path.exists():
        raise FileNotFoundError(f"The specified directory does not exist: {dir_path}")
    if not path.is_dir():
        raise FileNotFoundError(f"The specified path is not a directory: {dir_path}")

    if not predicates:
        raise ValueError("No valid predicates provided.")

    valid_predicates = []
    seen_predicates = set()

    for pred in predicates:
        if not callable(pred):
            continue
        pred_key = pred.__name__ if hasattr(pred, '__name__') else id(pred)
        if pred_key not in seen_predicates:
            valid_predicates.append(pred)
            seen_predicates.add(pred_key)

    if not valid_predicates:
        raise ValueError("No valid predicates provided.")

    result = {}
    try:
        for item in path.iterdir():
            item_name = item.name
            item_results = {}
            for pred in valid_predicates:
                try:
                    key = pred.__name__ if hasattr(pred, '__name__') else str(id(pred))
                    item_results[key] = pred(item_name)
                except Exception:
                    item_results[key] = False
            result[item_name] = item_results
    except Exception as e:
        raise RuntimeError(f"Error reading directory {dir_path}: {e}")

    return result

