import csv

def task_func(xml_content, output_csv_path):
    try:
        root = ET.fromstring(xml_content)
    except ET.ParseError as e:
        raise ET.ParseError(f"Failed to parse XML content: {e}")

    rows = []

    def extract_data(element, parent_tag=""):
        row = {}
        current_tag = f"{parent_tag}_{element.tag}" if parent_tag else element.tag

        if element.text and element.text.strip():
            row[current_tag] = element.text.strip()
        else:
            row[current_tag] = ""

        for attr_name, attr_value in element.attrib.items():
            attr_key = f"{current_tag}_{attr_name}"
            row[attr_key] = attr_value

        for child in element:
            child_data = extract_data(child, current_tag)
            for key, value in child_data.items():
                row[key] = value

        return row

    first_row = extract_data(root)
    rows.append(first_row)

    fieldnames = set()
    for row in rows:
        fieldnames.update(row.keys())
    fieldnames = sorted(fieldnames)

    try:
        with open(output_csv_path, 'w', newline='', encoding='utf-8') as csvfile:
            if rows:
                writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
                writer.writeheader()
                writer.writerows(rows)
    except IOError as e:
        raise IOError(f"Failed to write to CSV file: {e}")

