import time
import glob

def task_func(r_script_path: str, output_path: str, duration: int) -> (bool, str):
    if not os.path.isfile(r_script_path):
        return False, "R script not found."

    output_dir = os.path.dirname(output_path)
    if output_dir and not os.path.exists(output_dir):
        os.makedirs(output_dir)

    try:
        start_time = time.time()
        process = subprocess.Popen(
            ['Rscript', r_script_path],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True
        )

        while True:
            if process.poll() is not None:
                break
            if time.time() - start_time > duration:
                process.terminate()
                return False, "File not generated within the specified duration."
            time.sleep(0.1)

        stdout, stderr = process.communicate()
        if process.returncode != 0:
            return False, f"R script failed to execute: {stderr}"

    except Exception as e:
        return False, f"Error executing R script: {str(e)}"

    if '*' in output_path or '?' in output_path:
        matched_files = glob.glob(output_path)
        if not matched_files:
            return False, "File not generated within the specified duration."
    else:
        if not os.path.isfile(output_path):
            return False, "File not generated within the specified duration."

    return True, "File generated successfully within the specified duration."

