from random import randint, seed

def task_func(dictionary, item, sample_size=None, random_seed=None):
    df = pd.DataFrame.from_dict(dictionary, orient='index')
    positions = []
    for row_idx in df.index:
        for col_idx in df.columns:
            if df.loc[row_idx, col_idx] == item:
                positions.append((row_idx, col_idx))
    if random_seed is not None:
        seed(random_seed)
    if sample_size is not None:
        if len(positions) > sample_size:
            sampled_indices = set()
            while len(sampled_indices) < sample_size:
                sampled_indices.add(randint(0, len(positions) - 1))
            positions = [positions[i] for i in sorted(sampled_indices)]
    return positions, df

