import pandas as pd
import json
import os
import math
def task_func(json_data, output_dir=".", file_name="country_population_report.csv"):
    if not json_data or not json_data.strip():
        raise ValueError("JSON data is empty or invalid")

    try:
        data = json.loads(json_data)
    except json.JSONDecodeError as e:
        raise ValueError(f"Malformed JSON data: {e}")

    if not isinstance(data, list):
        raise ValueError("JSON data must be a list of country-population records")

    validated_data = []
    for idx, record in enumerate(data):
        if not isinstance(record, dict):
            raise ValueError(f"Each record must be a dictionary. Invalid record at index {idx}")

        if 'Country' not in record:
            raise ValueError(f"Missing 'Country' key in record at index {idx}")
        country = record['Country']
        if not isinstance(country, str):
            raise ValueError(f"Country name must be a string. Invalid type at index {idx}")

        if 'Population' not in record:
            raise ValueError(f"Missing 'Population' key in record at index {idx}")
        population = record['Population']
        if not isinstance(population, (int, float)):
            raise ValueError(f"Population must be numeric. Invalid type at index {idx}")
        if population < 0:
            raise ValueError(f"Population cannot be negative. Invalid value at index {idx}")

        if isinstance(population, float):
            population = int(math.floor(population))

        validated_data.append({"Country": country, "Population": population})

    df = pd.DataFrame(validated_data)
    df.reset_index(drop=True, inplace=True)

    file_path = os.path.join(output_dir, file_name)

    try:
        os.makedirs(output_dir, exist_ok=True)
    except OSError as e:
        raise IOError(f"Cannot create directory {output_dir}: {e}")

    try:
        df.to_csv(file_path, index=False)
    except IOError as e:
        raise IOError(f"Cannot write to file {file_path}: {e}")

    return file_path, df

