import os
import shutil
import glob

def task_func(src_dir, dest_dir, ext):
    if not os.path.exists(src_dir):
        raise FileNotFoundError(f"Source directory not found: {src_dir}")
    if not os.path.exists(dest_dir):
        raise FileNotFoundError(f"Destination directory not found: {dest_dir}")

    moved_files = []
    pattern = os.path.join(src_dir, f"*.{ext}")

    for file_path in glob.glob(pattern):
        if os.path.isfile(file_path):
            filename = os.path.basename(file_path)
            dest_path = os.path.join(dest_dir, filename)

            if not os.path.exists(dest_path):
                shutil.move(file_path, dest_path)
                moved_files.append(os.path.abspath(file_path))

    return moved_files

import subprocess
import os
import json
from datetime import datetime

def task_func(script_name='backup.sh', log_file='/home/user/backup_log.json'):
    if not os.path.isfile(script_name):
        raise FileNotFoundError(f"The script file '{script_name}' does not exist.")

    start_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    try:
        result = subprocess.run([script_name], check=True, capture_output=True, text=True)
        exit_status = result.returncode
    except subprocess.CalledProcessError as e:
        exit_status = e.returncode
        raise RuntimeError(f"Error executing the script '{script_name}': {e.stderr.strip() or e.stdout.strip()}")
    except Exception as e:
        raise RuntimeError(f"Unexpected error executing the script '{script_name}': {str(e)}")

    end_time = datetime.now().strftime('%Y-%m-%d %H:%M:%S')

    log_data = {
        'start_time': start_time,
        'end_time': end_time,
        'exit_status': exit_status
    }

    try:
        log_dir = os.path.dirname(log_file)
        if log_dir and not os.path.exists(log_dir):
            os.makedirs(log_dir)

        with open(log_file, 'w') as f:
            json.dump(log_data, f, indent=4)
    except Exception as e:
        raise RuntimeError(f"Failed to write log to '{log_file}': {str(e)}")

    return log_data

import json
import pandas as pd
from sklearn.preprocessing import MinMaxScaler
import matplotlib.pyplot as plt

def task_func(json_data: str, data_key: str):
    try:
        data = json.loads(json_data)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON string")

    keys = data_key.split('.')
    current = data
    for key in keys:
        if isinstance(current, dict) and key in current:
            current = current[key]
        else:
            raise KeyError(f"Key path '{data_key}' not found in the JSON data")

    if isinstance(current, (list, tuple)):
        original_series = pd.to_numeric(current, errors='coerce', dtype='float64')
    else:
        original_series = pd.to_numeric([current], errors='coerce', dtype='float64')

    if original_series.isna().all():
        raise ValueError(f"All values extracted from key '{data_key}' are non-numeric and could not be converted.")
    if original_series.empty:
        raise ValueError(f"No valid numerical data found in key '{data_key}'.")

    try:
        scaler = MinMaxScaler()
        normalized_values = scaler.fit_transform(original_series.values.reshape(-1, 1)).flatten()
        normalized_series = pd.Series(normalized_values, index=original_series.index, dtype='float64')
    except Exception:
        raise ValueError("Failed to apply Min-Max normalization")

    fig, ax = plt.subplots(figsize=(10, 6))
    ax.plot(original_series.index, original_series.values, label="Original Data", marker='o', linestyle='-')
    ax.plot(normalized_series.index, normalized_series.values, label="Normalized Data", marker='s', linestyle='--')
    ax.set_xlabel("Index")
    ax.set_ylabel("Value")
    ax.set_title("Comparison of Original and Normalized Data")
    ax.legend()
    ax.grid(True, alpha=0.3)

    return original_series, normalized_series, ax

