                with open(file_path, 'r', encoding='utf-8') as file:
                    data = json.load(file)
                    def count_keys(obj):
                        if isinstance(obj, dict):
                            for key in obj.keys():
                                key_count[key] = key_count.get(key, 0) + 1
                                count_keys(obj[key])
                        elif isinstance(obj, list):
                            for item in obj:
                                count_keys(item)
                    count_keys(data)
            except (json.JSONDecodeError, IOError):
                continue
    return key_count

