import json
import pandas as pd
import numpy as np
from collections import defaultdict

def task_func(input_file="data.json"):
    with open(input_file, 'r') as file:
        data = json.load(file)

    all_keys = set()
    for d in data:
        all_keys.update(d.keys())

    numeric_values = defaultdict(list)

    for d in data:
        for key in all_keys:
            value = d.get(key)
            if value is not None:
                if isinstance(value, (int, float)) and not (isinstance(value, float) and np.isnan(value)):
                    numeric_values[key].append(value)

    result_data = []
    for key in sorted(numeric_values.keys()):
        values = numeric_values[key]
        if values:
            mean_val = np.mean(values)
            median_val = np.median(values)
            result_data.append({'mean': mean_val, 'median': median_val})

    df = pd.DataFrame(result_data, index=sorted(numeric_values.keys())).sort_index()

    return df

